import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Cpu, LayoutDashboard, TrendingUp, LogOut } from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const location = useLocation();

  return (
    <nav className="nav-glass">
      <div className="nav-container">
        
        {/* Brand Side */}
        <Link to="/" className="flex items-center gap-3">
          <div className="p-2 bg-emerald-500/10 rounded-lg shadow-[0_0_15px_var(--accent-glow)]">
            <Cpu size={22} className="text-emerald-500" />
          </div>
          <span className="text-white font-bold tracking-[0.2em] text-sm uppercase hidden sm:block">
            Finify AI
          </span>
        </Link>

        {/* Navigation Side */}
        <div className="flex items-center gap-8">
          {user && (
            <>
              <Link 
                to="/dashboard" 
                className={`nav-link ${location.pathname === '/dashboard' ? 'nav-link-active' : ''}`}
              >
                <LayoutDashboard size={14} /> <span className="hidden md:inline">Dashboard</span>
              </Link>
              <Link 
                to="/generate" 
                className={`nav-link ${location.pathname === '/generate' ? 'nav-link-active' : ''}`}
              >
                <TrendingUp size={14} /> <span className="hidden md:inline">Strategy</span>
              </Link>
              
              <button onClick={logout} className="nav-link text-red-500/60 hover:text-red-400 ml-4">
                <LogOut size={16} />
              </button>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
